#!/usr/bin/env python3
"""
松哥系统 - 设备授权检查
整合三种授权模式：
1. Master设备白名单
2. 账号登录验证
3. License签名验证（支持设备绑定+使用期限）

优先级：Master > 账号 > License
"""

import argparse
import base64
import hashlib
import json
import os
import platform
import stat
import subprocess
import tempfile
import time
from pathlib import Path

DEFAULT_POLICY = "/var/minis/skills/songge/data/license_policy.json"
DEFAULT_ACCOUNTS = "/var/minis/skills/songge/data/accounts.json"
SYSTEM_SALT = "SONGGE_LICENSE_V1_2025"


def _run(cmd):
    try:
        return subprocess.check_output(cmd, stderr=subprocess.DEVNULL).decode().strip()
    except Exception:
        return ""


def _safe_read(path, limit=1024):
    """安全读取文件前N字节"""
    try:
        with open(path, "rb") as f:
            return f.read(limit).decode("utf-8", errors="ignore").strip()
    except Exception:
        return ""


# ============================================================
# 核心：设备指纹采集（与 get_device_hash.py 完全一致）
# ============================================================

def get_device_fingerprint_raw():
    """采集设备指纹，与学员端脚本保持一致"""
    parts = []

    # 1. 系统基础
    parts.append(platform.system())
    parts.append(platform.machine())
    parts.append(platform.version())
    parts.append(platform.processor())

    # 2. CPU信息哈希
    cpu_raw = _safe_read("/proc/cpuinfo", 800)
    if cpu_raw:
        parts.append(hashlib.sha256(cpu_raw.encode()).hexdigest()[:16])
    else:
        parts.append("")

    # 3. 内存总量
    mem_total = ""
    try:
        with open("/proc/meminfo") as f:
            first_line = f.readline()
            kb = int(''.join(filter(str.isdigit, first_line.split("kB")[0])))
            mem_total = str(kb // 1024)
    except Exception:
        pass
    parts.append(mem_total)

    # 4. 主机名
    hostname = _run(["hostname"]) or _safe_read("/etc/hostname") or ""
    parts.append(hostname)

    # 5. 系统固定盐
    parts.append(SYSTEM_SALT)

    return "|".join(parts)


def get_device_hash():
    """计算设备哈希（与学员端脚本一致）"""
    return hashlib.sha256(get_device_fingerprint_raw().encode()).hexdigest()


def load_json(path):
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def canonical_payload(payload: dict) -> bytes:
    return json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":")).encode()


def verify_with_public_key(payload: dict, signature_b64: str, public_key_path: str) -> bool:
    try:
        data = canonical_payload(payload)
        sig = base64.b64decode(signature_b64.encode())
        with tempfile.NamedTemporaryFile(delete=False) as f_data, tempfile.NamedTemporaryFile(delete=False) as f_sig:
            f_data.write(data)
            f_data.flush()
            Path(f_sig.name).write_bytes(sig)
            cmd = ["openssl", "dgst", "-sha256", "-verify", public_key_path, "-signature", f_sig.name, f_data.name]
            subprocess.check_call(cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        Path(f_f_data.name).unlink(missing_ok=True)
        Path(f_sig.name).unlink(missing_ok=True)
        return True
    except Exception:
        return False


def check_by_device(policy_path):
    """方式1: Master设备白名单（松哥自己用）"""
    policy = load_json(policy_path)
    dev_hash = get_device_hash()
    if dev_hash in policy.get("master_devices", []):
        return {"status": "PASS_MASTER", "device_hash": dev_hash}
    return None


def check_by_account():
    """方式2: 账号登录验证（含期限）"""
    if not os.path.exists(DEFAULT_ACCOUNTS):
        return None

    db = load_json(DEFAULT_ACCOUNTS)
    device = get_device_hash()
    now = int(time.time())

    for acc in db.get("accounts", []):
        if device in acc.get("devices", []) and acc.get("active", False):
            if acc["expires_at"] > now:
                return {
                    "status": "PASS_ACCOUNT",
                    "account_id": acc["account_id"],
                    "account_name": acc["name"],
                    "expires_at": acc["expires_at"]
                }
            else:
                return {
                    "status": "FAIL",
                    "reason": "license_expired",
                    "message": f"账号已过期，到期时间：{time.strftime('%Y-%m-%d', time.localtime(acc['expires_at']))}"
                }
    return None


def check_by_license(policy_path):
    """方式3: License签名验证（含设备绑定+使用期限）"""
    policy = load_json(policy_path)
    lic_path = policy.get("license_path")

    if not lic_path or not os.path.exists(lic_path):
        return None

    try:
        lic = load_json(lic_path)
        payload = lic.get("payload", {})
        if not isinstance(payload, dict):
            return None

        # 校验 payload 字段一致性
        for k in ["student_id", "issued_at", "expires_at"]:
            if str(lic.get(k)) != str(payload.get(k)):
                return None

        # 验证签名
        pub_path = policy.get("public_key_path")
        if not pub_path or not os.path.exists(pub_path):
            return None

        if not verify_with_public_key(payload, lic["signature"], pub_path):
            return None

        # 使用期限检查
        now = int(time.time())
        expires_at = int(payload.get("expires_at", 0))

        if expires_at <= now:
            return {
                "status": "FAIL",
                "reason": "license_expired",
                "message": f"授权已过期，到期时间：{time.strftime('%Y-%m-%d', time.localtime(expires_at))}"
            }

        return {
            "status": "PASS_LICENSE",
            "student_id": payload.get("student_id"),
            "expires_at": expires_at
        }
    except Exception:
        return None


def check(policy_path=DEFAULT_POLICY):
    """
    综合授权检查
    优先级：Master > 账号 > License
    """
    policy = load_json(policy_path)
    deny = policy.get("deny_message", "未检测到有效授权，系统拒绝分析与输出。请先完成绑定。")

    # 方式1: Master设备
    result = check_by_device(policy_path)
    if result:
        return result

    # 方式2: 账号登录
    result = check_by_account()
    if result:
        return result

    # 方式3: License
    result = check_by_license(policy_path)
    if result:
        return result

    # 全部失败 → 拒绝
    return {"status": "FAIL", "reason": "no_authorization", "message": deny}


def device():
    """获取当前设备哈希（与学员端一致）"""
    return {"device_hash": get_device_hash()}


def main():
    p = argparse.ArgumentParser(description="松哥系统设备授权检查")
    p.add_argument("action", choices=["device", "check", "check-master", "check-account", "check-license"])
    p.add_argument("--policy", default=DEFAULT_POLICY)
    a = p.parse_args()

    if a.action == "device":
        print(json.dumps(device(), ensure_ascii=False))
    elif a.action == "check":
        print(json.dumps(check(a.policy), ensure_ascii=False))
    elif a.action == "check-master":
        print(json.dumps(check_by_device(a.policy) or {"status": "NOT_MASTER"}, ensure_ascii=False))
    elif a.action == "check-account":
        print(json.dumps(check_by_account() or {"status": "NO_ACCOUNT"}, ensure_ascii=False))
    elif a.action == "check-license":
        print(json.dumps(check_by_license(a.policy) or {"status": "NO_LICENSE"}, ensure_ascii=False))


if __name__ == "__main__":
    main()
